17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const aliveKeys = new Set(cells.map(cellKey));
19	  const candidates = new Map<string, Cell>();
20	
21	  for (const cell of cells) {
22	    for (const candidate of [cell, ...neighborsOf(cell)]) {
23	      candidates.set(cellKey(candidate), candidate);
24	    }
25	  }
26	
27	  const countLiveNeighbors = (cell: Cell): number =>
28	    neighborsOf(cell).filter((n) => aliveKeys.has(cellKey(n))).length;
29	
30	  return [...candidates.values()].filter((cell) =>
31	    survives(aliveKeys.has(cellKey(cell)), countLiveNeighbors(cell))
32	  );
33	}
